sp_css.css:
/* ============================= */
/* GLOBAL TYPOGRAPHY & BACKGROUND */
/* ============================= */

/* Base (applies everywhere in Service Portal) */
body,
.sp-page,
.sp-page-root {
  font-family: "Segoe UI", -apple-system, BlinkMacSystemFont, Arial, sans-serif;
  font-size: 14px;
  line-height: 1.5;
  background-color: #f1f5f9;
  color: #0f172a;
  
}
.select-radius
{
	border-radius: 1rem;
}

.container
{
	padding-top: 1.6rem !important;
}
.sp-page .container {
  padding-top: 3.2rem !important;
}

.sp-page .row {
  margin-top: 3.2rem !important;
}

/* Headings */
h1, .h1 {
  font-size: 26px !important;
  font-weight: 700 !important;
  margin: 0 0 6px 0;
}

h2, .h2 {
  font-size: 20px !important;
  font-weight: 700  !important;
  margin: 0 0 6px 0;
}

h3, .h3 {
  font-size: 16px !important;
  font-weight: 600 !important;
  margin: 0 0 4px 0;
}

/* Paragraphs */
p {
  font-size: 14px !important;
  margin: 0;
}

/* Small / secondary text */
small,
.text-sm {
  font-size: 12px !important;
  color: #64748b;
}

/* Labels (forms) */
label {
  font-size: 13px;
  font-weight: 500;
  color: #374151;
}

/* Inputs / selects / textarea */
input,
select,
textarea {
  font-family: inherit;
  font-size: 14px;
}

/* Buttons */
button {
  font-family: inherit;
  font-size: 14px;
}

/* Primary Button (Black) */
.btn-primary {
  background-color: #000000 !important;
  color: #ffffff;
  border: none;
  border-radius: 6px;
  padding: 8px 16px;
  font-size: 14px;
  cursor: pointer;
}

/* Hover effect */
.btn-primary:hover {
  background-color: #1a1a1a;
}

/* Optional: Active click */
.btn-primary:active {
  background-color: #333333;
}

